INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('24.º, dos artigos 53.º a 60.º, dos artigos 64.º a 66.º, dos n.os 1, 3 e 4 do artigo 84.º, do artigo 85.º, dos n.os 1 e 4 do artigo 86.º, do artigo 87.º, dos artigos 89.º e 90.º, das alíneas b) e d) do n.º 6 do artigo 91.º, do n.º 1 do artigo 92.º, dos artigos 93.º a 98.º, do artigo 100.º, do artigo 102.º, do artigo 105.º, dos artigos 107.º a 109.º, dos artigos 111.º a 114.º, do artigo 118.º, dos artigos 154.º a 157.º, do artigo 173.º, do artigo 180.º, do artigo 257.º, do n.º 1 do artigo 259.º, do artigo 260.º, das alíneas e), p) e v) do artigo 261.º e do artigo 264.º;
